class Solution:
    def findMinimumOperations(self, s1: str, s2: str, s3: str) -> int:
        def common_prefix_length(s1, s2, s3):
            length = 0
            for c1, c2, c3 in zip(s1, s2, s3):
                if c1 == c2 == c3:
                    length += 1
                else:
                    break
            return length

        common_length = common_prefix_length(s1, s2, s3)
        if common_length == 0:
            return -1

        operations = len(s1) + len(s2) + len(s3) - 3 * common_length
        return operations
```
